<?php
declare(strict_types=1);
$root=require dirname(__DIR__).'/bootstrap/app.php';
use Vigilancia\Database\Connection;use Vigilancia\Repositories\PermissionRepository;use Vigilancia\Repositories\SupervisionRepository;use Vigilancia\Services\AuthService;use Vigilancia\Services\AuthorizationService;use Vigilancia\Support\Config;use Vigilancia\Support\Session;
Session::start();$pdo=Connection::make(Config::database());$auth=new AuthService($pdo);$actor=$auth->currentOrNull();if(!$actor){http_response_code(401);exit('Debes iniciar sesión.');}$authorization=new AuthorizationService(new PermissionRepository($pdo));try{$authorization->require($actor,'supervisions.manage');}catch(Throwable){http_response_code(403);exit('Acceso denegado.');}$repo=new SupervisionRepository($pdo);$file=$repo->evidence((int)($_GET['id']??0));if(!$file||!$repo->inScope($actor,(int)$file['location_id'])){http_response_code(404);exit('Evidencia no encontrada.');}$path=$root.'/'.ltrim((string)$file['file_path'],'/');$storage=realpath($root.'/storage/supervisions');$real=realpath($path);if(!$storage||!$real||!is_file($real)||!str_starts_with($real,$storage.DIRECTORY_SEPARATOR)){http_response_code(404);exit('Archivo no disponible.');}header('Content-Type: '.$file['mime_type']);header('Content-Length: '.filesize($real));header('Content-Disposition: inline; filename="supervision-'.$file['supervision_id'].'-evidencia-'.$file['id'].'.'.pathinfo($real,PATHINFO_EXTENSION).'"');header('X-Content-Type-Options: nosniff');readfile($real);
